class IndentationRuleReproductionTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Issue reproduction - parentheses in if block`() {
        val code = """
            val pass = if (condition1) {
                (
                    condition2
                )
            } else {
                condition3
            }
        """.trimIndent()
        indentationRuleAssertThat(code)
            .hasNoLintViolations()
    }

    @Test
    fun `Issue reproduction - parentheses in if block with ktlint_official`() {
        val code = """
            val pass = if (condition1) {
                (
                    condition2
                )
            } else {
                condition3
            }
        """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }
}
"}

{"content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.rule.engine.core.api.ElementType
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.jetbrains.kotlin.com.intellij.lang.ASTNode
import org.jetbrains.kotlin.psi.KtPsiFactory
import org.junit.jupiter.api.Test

class AstPrinter {
    @Test
    fun `Print AST`() {
        val code = """
            val pass = if (condition1) {
                (
                    condition2
                )
            } else {
                condition3
            }
        """.trimIndent()

        val ktPsiFactory = KtPsiFactory(null as com.intellij.openapi.project.Project?)
        val file = ktPsiFactory.createFile("test.kt", code)
        printAst(file.node)
    }

    private fun printAst(node: ASTNode, indent: String = "") {
        println("${indent}${node.elementType} : ${node.text.replace("\n", "\\n")}")
        var child = node.firstChildNode
        while (child != null) {
            printAst(child, indent + "  ")
            child = child.treeNext
        }
    }
}
